new file mode 100644
index 0000000..83c9a3e
--- /dev/null
+++ b/src/collateral.rs
@@ -0,0 +1,126 @@
+use crate::error::{Error, Result};
+use crate::quotes::enclave_identity::EnclaveIdentityV2;
+use crate::quotes::qe_report::QeReportBody;
+use crate::tcb_info::cert::verify_certchain_signature;
+
+fn decode_hex(s: &str) -> Result<Vec<u8>> {
+    let s = s.trim();
+    if s.len() % 2 != 0 {
+        return Err(Error::VerificationError(
+            "invalid hex-encoded QE identity signature".into(),
+        ));
+    }
+    let mut out = Vec::with_capacity(s.len() / 2);
+    let bytes = s.as_bytes();
+    for i in (0..bytes.len()).step_by(2) {
+        let hi = (bytes[i] as char)
+            .to_digit(16)
+            .ok_or_else(|| Error::VerificationError("invalid hex digit".into()))?;
+        let lo = (bytes[i + 1] as char)
+            .to_digit(16)
+            .ok_or_else(|| Error::VerificationError("invalid hex digit".into()))?;
+        out.push(((hi << 4) | lo) as u8);
+    }
+    Ok(out)
+}
+
+pub(crate) fn verify_qe_identity_signature(
+    qe_identity_json: &str,
+    qe_identity_signature_hex: &str,
+    qe_identity_issuer_chain_pem: &str,
+) -> Result<()> {
+    let sig = decode_hex(qe_identity_signature_hex)?;
+    verify_certchain_signature(
+        qe_identity_issuer_chain_pem,
+        qe_identity_json.as_bytes(),
+        &sig,
+    )
+}
+
+pub(crate) fn enforce_qe_identity_policy(
+    qe_identity: &EnclaveIdentityV2,
+    qe_report: &QeReportBody,
+) -> Result<()> {
+    let expected = &qe_identity.enclave_identity;
+
+    if qe_report.mrsigner != expected.mrsigner {
+        return Err(Error::VerificationError(
+            "QE report MRSIGNER does not match QE identity".into(),
+        ));
+    }
+
+    if qe_report.isvprodid != expected.isvprodid {
+        return Err(Error::VerificationError(
+            "QE report ISVPRODID does not match QE identity".into(),
+        ));
+    }
+
+    if qe_report.isvsvn < expected.isvsvn {
+        return Err(Error::VerificationError(
+            "QE report ISVSVN is lower than required by QE identity".into(),
+        ));
+    }
+
+    Ok(())
+}
