+import assert from 'assert';
+import binaryParser from '../../../../../lib/parsers/binary_parser.js';
+
+describe('binary parser timezone sanitization', () => {
+  const field = {
+    columnType: 10
+  };
+
+  const config = {
+    timezone: 'Z'
+  };
+
+  it('accepts valid timezone values', () => {
+    assert.doesNotThrow(() =>
+      binaryParser.readCodeFor(field, config, { timezone: '+00:00' }, 0)
+    );
+    assert.doesNotThrow(() =>
+      binaryParser.readCodeFor(field, config, { timezone: 'local' }, 0)
+    );
+    assert.doesNotThrow(() =>
+      binaryParser.readCodeFor(field, config, { timezone: 'Z' }, 0)
+    );
+  });
+
+  it('rejects invalid timezone values', () => {
+    assert.throws(() => binaryParser.readCodeFor(field, config, { timezone: "Z');process.exit();//" }, 0), /Invalid timezone/);
+  });
+});
